var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"검사 결과, 체내의 침식 바이러스는 모두 소멸했어요.","JPN":"検査結果、体内の侵食ウイルスはすべて消滅しました。","ENG":"The test results show that the internal Corruption virus has been completely eradicated.","TWN":"檢查結果顯示，體內的侵蝕病毒已經完全消滅了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"이제 한 시름 덜었군요. 고생하셨어요, 경관님.","JPN":"これで一安心です。お疲れ様でした、お巡りさん。","ENG":"At least that's one worry off our shoulders. Great work, officer.","TWN":"現在可以稍微鬆口氣了。辛苦了，警官。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"다른 피해자들은 어떻죠?","JPN":"他の被害者はどうしていますか？","ENG":"What about the other victims?","TWN":"其他受害者情況如何？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"환자 검진은 제 소관이 아니라서요. 다들 멀쩡히 깨어났으니 괜찮겠죠.","JPN":"患者の診断は私の管轄外なので。みなさん無事目覚めたので大丈夫でしょう。","ENG":"I'm not in charge of patient exams, but everyone seems to have woken up fine.","TWN":"患者的檢查不歸我管。但大家都已經醒過來了，應該沒問題的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"애니 양도 무사히 회복하고 있대요. 그러니 한숨 돌리세요, 경정님.","JPN":"エニーさんも無事回復しているそうです。だから休んでください、警視様。","ENG":"Annie is recovering well too. So rest assured, Major.","TWN":"安妮也在順利康復，所以可以稍稍放寬心了，長官。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"…응.","JPN":"……うん。","ENG":"...Okay.","TWN":"……嗯。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"강소영 경위도 고생 많았어.","JPN":"マエカワ警部補もお疲れ様。","ENG":"Lieutenant Kang, good work.","TWN":"姜素英警官，你也辛苦了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"뭐, 저도 최선을 다하긴 했지만… 진짜로 활약을 하신 분은 따로 있으니까요.","JPN":"まぁ、私も最善を尽くしましたけど……本当に活躍した方は他にいますから。","ENG":"Well, I did my best, but the real hero is someone else.","TWN":"嗯，雖然我也盡力了……但真正起到關鍵作用的另有其人。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"나중에 한 번 찾아가서 정식으로 감사인사를 드리죠.","JPN":"後日訪ねて行って正式にお礼を言いましょう。","ENG":"We should go visit later and thank her properly.","TWN":"以後找時間正式去感謝一下她吧。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"솔로베 말이지? 지금은 어디에 있는데?","JPN":"ソロベーのことね？　今はどこにいるの？","ENG":"You're talking about Solovey, right? Where is she?","TWN":"你是說蘇羅薇嗎？她現在在哪？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L14_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"쇼핑을 다녀온다던데요?","JPN":"ショッピングに行くらしいですよ？","ENG":"I heard she's out shopping?","TWN":"聽說她去逛街了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"오오…!","JPN":"おお……！","ENG":"Wow...!","TWN":"哇喔……！"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"LAUGH2"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_BIRDCAGE_IN_TRAILER_103"},{"id":"L18_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"이거 귀여워요! 이것도!","JPN":"これ可愛いです！　これも！","ENG":"This one's cute! And this one too!","TWN":"好可愛！這個也好可愛！"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"LAUGH2"},"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_BIRDCAGE_IN_TRAILER_104"},{"id":"L20_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"여기 있는 인형 전부 다 주세요!!","JPN":"ここにあるぬいぐるみ全部ください！！","ENG":"I'll take all the dolls here, please!!","TWN":"請把這裡所有的娃娃都幫我包起來！"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_BIRDCAGE_IN_TRAILER_105"},{"id":"L22_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"감사합니다. 직원들이 포장할 동안 잠시 기다려주세요.","JPN":"ありがとうございます。店員がいま包装いたしますので、少々お待ちください。","ENG":"Thank you. Please wait a moment while the staff wraps it up.","TWN":"謝謝你，那麼在店員包裝的時候，請你稍等一下。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"솔로베, 정말 괜찮겠어?","JPN":"ソロベー、本当に大丈夫？","ENG":"Solovey, are you really sure about this?","TWN":"蘇羅薇，真的沒問題嗎？"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_DESPAIR"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ALT_C_SEO_YOON_PR_IN_TRAILER_71"},{"id":"L24_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"기껏 받아낸 관리국 보수금을 인형에다 전부 써버려도?","JPN":"せっかく管理局から貰った報酬なのに全部ぬいぐるみに使って。","ENG":"You're really spending the whole reward from the Administration on dolls?","TWN":"好不容易拿到了管理局獎金，全都花在娃娃上沒關係嗎？"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ALT_C_SEO_YOON_PR_IN_TRAILER_72"},{"id":"L25_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"괜찮아요. 돈은 가지고 있는 것보다 좋아하는 일에 쓰는 게 더 즐겁거든요.","JPN":"大丈夫です。お金は持っているより自分が好きなことに使う方が楽しいですから。","ENG":"It's fine. Spending money on what I love is more enjoyable than having it.","TWN":"沒關係的，與其把錢握在手裡，不如花在喜歡的事情上還更開心些，不是嗎？"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_BIRDCAGE_IN_TRAILER_106"},{"id":"L27_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"뭐… 틀린 말은 아니네.","JPN":"まあ……間違ってはないけど。","ENG":"Well, you're not wrong.","TWN":"嗯……也對。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_LAUGH"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ALT_C_SEO_YOON_PR_IN_TRAILER_73"},{"id":"L29_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그런데 언니는 여기 와도 돼요? 병원에서 치료받지 않아도 되나요?","JPN":"ところで姉さんはここにいてもいいんですか？　病院で治療を受けた方が、いいんじゃないですか？","ENG":"Are you sure you can be here, Sis? Shouldn't you be at the hospital for treatment?","TWN":"但姊姊，你這樣出來真的可以嗎？不用留在醫院治療嗎？"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_BIRDCAGE_IN_TRAILER_107"},{"id":"L30_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"견딜 만해. 병원 신세 진 지 얼마 안 됐는데, 또 소독약 냄새를 맡고 싶지도 않고.","JPN":"我慢できるくらいよ。退院してからそう経っていないのに、また消毒薬の匂いを嗅ぐのも嫌だから。","ENG":"I can handle it. I just got out of the hospital, and I don't want to smell antiseptic again.","TWN":"還撐得住。前段時間才住過院，不想這麼快又聞到消毒藥水的味道。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ALT_C_SEO_YOON_PR_IN_TRAILER_74"},{"id":"L34_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"돌아가는 길엔 같이 돈까스나 먹을까? 괜찮은 맛집을 알거든.","JPN":"帰りに一緒にとんかつでも食べる？　美味しい店を知ってるの。","ENG":"How about we get some pork cutlets on the way back? I know a great place.","TWN":"回去的路上一起去吃炸豬排怎麼樣？我知道一家好吃的店。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ALT_C_SEO_YOON_PR_IN_TRAILER_75"},{"id":"L35_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"앗…! 네에! 먹을래요!","JPN":"あっ……！　はい！　食べます！","ENG":"Ah...! Yes! I'd love to!","TWN":"啊……！好啊，我想吃！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"LAUGH2"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_BIRDCAGE_IN_TRAILER_108"},{"id":"L36_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"두 개 먹어도 돼요?","JPN":"2つ食べてもいいですか？","ENG":"Can I eat two?","TWN":"我可以吃兩份嗎？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_BIRDCAGE_IN_TRAILER_109"},{"id":"L37_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"그야 당연하지.","JPN":"もちろんよ。","ENG":"Sure.","TWN":"當然可以。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ALT_C_SEO_YOON_PR_IN_TRAILER_76"},{"id":"L38_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"어차피 살 찌는 건 너니까.","JPN":"どうせ太るのはあなただからね。","ENG":"You're the one who's going to get fat anyway.","TWN":"反正長肉的是你。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ALT_C_SEO_YOON_PR_IN_TRAILER_77"},{"id":"L41_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"어머, 이게 다 뭐죠?","JPN":"あら、これはどうしたの？","ENG":"Oh my, what's all this?","TWN":"哇，這都是些什麼啊？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"복도에 아이들이 전부 인형을 갖고 놀고 있네요.","JPN":"廊下にいる子どもたちがみんな、ぬいぐるみを持って遊んでいますね。","ENG":"The kids in the hallway are all playing with dolls.","TWN":"走廊上的孩子們全都在抱著娃娃玩呢。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"NURSE_EXTRA_NULL_NULL","text":{"KOREA":"이번 3-3구획 사건 아시죠? 거기 참전한 카운터 분이 환자들한테 선물한 거래요.","JPN":"今回3-3区画での事件ご存じですよね？　そこで戦ったカウンターの方が患者たちにプレゼントしたそうですよ。","ENG":"You know about the block 3-3 incident, right? A Counter who took part there gave the patients gifts.","TWN":"聽說這次3-3隔離區事件了嗎？好像是一位參戰的制裁者送給患者們娃娃的。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"NURSE_EXTRA_NULL_NULL","text":{"KOREA":"귀여운 인형이 있으면 행복해져서 금방 나을 거라네요.","JPN":"可愛いぬいぐるみがあると幸せになってすぐ治るからって。","ENG":"She says if you have a cute doll, you'll feel happy and recover quickly.","TWN":"如果有可愛的娃娃心情就會變好，這樣恢復起來也會很快吧。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"자, 이건 애니 거예요!","JPN":"さ！　これはエニーの分です。","ENG":"Here! This one's for you, Annie.","TWN":"來！這個是給安妮的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"어? 나도 주는 거야?","JPN":"え？　私にもくれるの？","ENG":"What? You're giving me one too?","TWN":"啊？也給我嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"고마워.","JPN":"ありがとう。","ENG":"Thanks.","TWN":"謝謝。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"귀엽죠? 끌어안으면 엄청 푹신하다고요.","JPN":"可愛いでしょう？　抱っこするとすごくフワフワなんですよ。","ENG":"Isn't it cute? It's super soft when you hug it.","TWN":"是不是很可愛？抱起來還特別柔軟呢！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"응… 되게 부드럽다. 아픈 것도 다 잊을 정도야.","JPN":"うん……本当に柔らかい。痛みを忘れるほどに。","ENG":"Yeah... it's really soft. It makes me forget all my pain.","TWN":"嗯……真的很軟，感覺疼痛都消失了一樣。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"헤헤.","JPN":"へへ。","ENG":"Hehe.","TWN":"嘿嘿。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"그런데 어떻게 이겼어?","JPN":"ところで、どうやって勝ったの？","ENG":"So, how did you win?","TWN":"但是，你到底是怎麼贏的？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"니블이란 녀석… 웬만한 카운터보다 강하고 프로들도 속일 정도로 교활했다던데.","JPN":"ニブルっていうやつ……並みのカウンターよりも強いし、プロも騙されるほどずる賢かったって言ってたよ。","ENG":"I heard Nibble... was stronger than most Counters and sly enough to fool even pros.","TWN":"聽說蠶食那傢伙比一般制裁者還強，狡猾到連專業人士都能騙過呢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"맞아요. 그래서 약점을 이용했거든요.","JPN":"そうなんです。だから弱点を利用しました。","ENG":"That's right. So, I used her weakness.","TWN":"是的，所以我利用了她的弱點。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"약점? 그게 뭐였는데?","JPN":"弱点？　何だったの？","ENG":"Weakness? What was it?","TWN":"弱點？是什麼？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"니블은 카운터의 힘과 생각을 훔쳐 강해지는 괴물…","JPN":"ニブルはカウンターの力と知性を盗んで強くなる化け物で……","ENG":"Nibble is a monster that steals the powers and thoughts of Counters to get stronger...","TWN":"蠶食是一種竊取制裁者力量和思考，從而變強的怪物……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"너무 강하고 똑똑하기까지 해서, 처음엔 어떻게 이겨야 할지 몰랐어요.","JPN":"とても強くて頭もいいので、最初はどうしたら勝てるのかわからなかったんです。","ENG":"She was so strong and smart that, at first, I didn't know how to defeat her.","TWN":"她不僅很強還很聰明，一開始我根本不知道該怎麼對付她。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그런데… 남들에게 빼앗은 똑똑함이라 그런지, 정작 자기 자신에 대해선 잘 모르더라고요.","JPN":"でも……他人から奪った頭脳だからなのか、自分自身のことはあまり知らなかったんです。","ENG":"But... perhaps because she stole intelligence from others, she didn't really understand herself.","TWN":"但是……也許是因為她的聰明才智都是從別人那裡偷來的，所以她對自己其實一無所知。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그래서 녀석이 모르는 사실을 이용했을 뿐이에요.","JPN":"だからニブルがわからないことを利用しただけです。","ENG":"That's why I took advantage of what she didn't know.","TWN":"所以，我只是利用了她所不知道的事實而已。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"솔로베는… 대단하구나.","JPN":"ソロベーは……すごいね。","ENG":"Solovey... you're amazing.","TWN":"蘇羅薇……你真的好厲害啊。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"처음엔 아무에게나 돈을 주는 순진한 바보라고 생각했는데…","JPN":"最初は誰にでもお金をあげる無邪気なバカだと思ったのに……","ENG":"At first, I thought you were a naive fool who would give money to anyone...","TWN":"起初我還以為你只是個隨便給別人錢的，天真的傻瓜……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"바보는 나였어. 너처럼 좋은 애한테 거짓말을 하고 돈까지 빼앗았으니까.","JPN":"バカは私だった。あんたみたいにいい子にウソを言ってお金までだまし取って。","ENG":"But I was the fool. I lied to a good person like you and even took your money.","TWN":"原來真正的傻瓜是我，不僅騙了你這樣的好人，還搶了你的錢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"애니는 그 돈을 소중한 사람을 돕기 위해 쓴 거잖아요?","JPN":"エニーはそのお金をお母さんを助けるために使ったんですよね？","ENG":"Annie, you used that money to help the one you cherish, right?","TWN":"但你是為了用那筆錢幫助媽媽，不是嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"저도 그래서 준 돈이니까. 한 번도 빼앗겼다고 생각한 적 없어요.","JPN":"私もそのために渡しましたから。一度も取られたと思ったことはありません。","ENG":"That's the reason why I gave that money to you. I've never thought you stole it from me.","TWN":"所以我才願意把錢給你，我從來沒覺得拿錢是被你騙走的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"충분히 잘 하고 있다고 생각해요.","JPN":"十分ちゃんとやっていると思います。","ENG":"I think you're doing just fine.","TWN":"你做得已經很好了，我真的是這麼覺得的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"나 앞으로는 열심히 살게! 너처럼 되기 위해서!","JPN":"私これからは頑張って生きる！　あんたみたいになるために！","ENG":"I'm going to live diligently from now on! To be like you!","TWN":"我以後一定會努力生活！變得像你一樣！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L30_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어… 저처럼요?","JPN":"え……私みたいにですか？","ENG":"Huh... like me?","TWN":"呃……像我一樣？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"SURPRISE2"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"관리국 심사 받고, 일자리도 구하고…! 돈도 갚을 테니까!","JPN":"管理局から審査も受けて、仕事も探して……！　お金も返すから！","ENG":"I'll go through the Administration evaluation, find a job... and pay back the money!","TWN":"接受管理局審查，然後找到工作……！錢我也會還的！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"그러니까… 솔로베.","JPN":"だから……ソロベー。","ENG":"So... Solovey.","TWN":"所以……蘇羅薇。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"네가 앞으로도 날 지켜 봐줄래?","JPN":"これからもあんたが私を見ていてくれる？","ENG":"Will you keep watching over me from now on?","TWN":"你能以後也一直看著我成長嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"널 동경하는 거네.","JPN":"あなたに憧れているのね。","ENG":"You're being admired.","TWN":"她很仰慕你呢。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"동경… 이라고요?","JPN":"憧れですか？","ENG":"Admired...?","TWN":"仰慕？"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"네가 누군가의 마음 속 영웅이 됐다는 뜻이야.","JPN":"あなたが誰かの心の中の英雄になったっていうこと。","ENG":"It means you've become someone's hero in their heart.","TWN":"表示你已經成為了某個人心中的英雄了呢。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"내가… 애니의 마음 속 영웅…","JPN":"私が……エニーの心の中の英雄……","ENG":"I'm Annie's hero...","TWN":"我是安妮的英雄……"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"그래서? 영웅이 된 소감은 어때?","JPN":"それで？　英雄になった気分はどう？","ENG":"How does it feel to become a hero?","TWN":"成為英雄的感受如何？"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"누군가에게 동경 받는다는 건… 조금 부끄럽지만…","JPN":"誰かに憧れられるのは……少し恥ずかしいですけど……","ENG":"Being admired by someone... is a little embarrassing, but…","TWN":"被別人仰慕……雖說有些害羞……"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"더 열심히 하고 싶어요! 동경 받는 사람으로서, 누구도 실망하지 않도록!","JPN":"もっと頑張りたいです！　憧れられる人として、誰からもがっかりされないように！","ENG":"I want to try harder! As someone who is admired, I won't let anyone down!","TWN":"但我想更加努力！作為被仰慕的人，不讓任何人失望！"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그러니까, 앞으로도 잘 부탁드려요! 서윤 언니!","JPN":"だから、これからもよろしくお願いします！　シズカ姉さん！","ENG":"So, I ask for your continued help! Sis!","TWN":"所以，以後也請多多關照！徐芸姊姊！"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"후후, 기본 자질은 이미 충분하다고 생각하지만… 아직 배움이 필요 없는 건 아니니까.","JPN":"ふふ、基本的な資質はもう十分だと思うけど……学びというものは尽きないものだからね。","ENG":"Haha, I think you already have the basic qualities... but there's still room for learning.","TWN":"呵呵，雖然我覺得你的基本素質已經足夠……但這並不表示你已經沒有東西可學。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"좋아. 내일부터 다시 훈련을 시작해보자.","JPN":"いいよ。明日からまた訓練に入ろう。","ENG":"All right. Let's start training again tomorrow.","TWN":"好吧，從明天開始重新訓練吧。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"네!","JPN":"はい！","ENG":"Okay!","TWN":"嗯！"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};